import React, { useState } from 'react';
import { Sword, Pickaxe, Shield, Zap, Skull, Flame, Droplets, ShieldAlert } from 'lucide-react';
import type { Hero, Building } from '../engine/types';
import type { Synergy } from '../engine/synergies';
import { SYNERGY_DEFINITIONS } from '../engine/synergies';

import { HeroDetailModal } from './modals/HeroDetailModal';

import { Info, Crown } from 'lucide-react'; // Phase 58


interface HeroListProps {
    heroes: Hero[];
    actions: any;
    activeSynergies?: Synergy[];
    buildings?: Building[];
    heroBonds?: Record<string, { xp: number, level: number, type: 'comrades' | 'rivals' | 'soulmates' }>;
}

export const HeroList: React.FC<HeroListProps> = ({ heroes, actions, activeSynergies = [], buildings = [], heroBonds = {} }) => {
    const [viewingHero, setViewingHero] = useState<Hero | null>(null);
    // Update 74

    const getContributingSynergies = (hero: Hero) => {
        if (!activeSynergies || activeSynergies.length === 0) return [];
        return activeSynergies.filter(syn => {
            const def = SYNERGY_DEFINITIONS.find(d => d.id === syn.id);
            if (!def) return false;

            // Check Class Set
            if (def.classSet && def.classSet.includes(hero.class)) return true;
            // Check Elements
            if (def.elements && def.elements.includes(hero.element)) return true;
            // Check Exact Class (Legacy)
            if (def.classes && def.classes.includes(hero.class)) return true;
            // Check Generic Count (e.g. 5 heroes)
            if (def.minCount && !def.classSet && !def.classes && !def.elements) return true;

            return false;
        });
    };

    const getSynergyIcon = (type: string) => {
        switch (type) {
            case 'burn': return <Flame size={10} className="text-orange-500" />;
            case 'freeze': return <Droplets size={10} className="text-cyan-400" />;
            case 'mitigation': return <Shield size={10} className="text-yellow-500" />;
            case 'cd_reduction': return <Zap size={10} className="text-purple-400" />;
            case 'crit_dmg': return <Sword size={10} className="text-red-500" />;
            default: return <Zap size={10} className="text-yellow-200" />;
        }
    };

    return (
        <div className="w-full bg-gray-800 p-2 grid grid-cols-2 md:grid-cols-3 gap-2">

            <HeroDetailModal
                isOpen={!!viewingHero}
                onClose={() => setViewingHero(null)}
                hero={viewingHero ? heroes.find(h => h.id === viewingHero.id) || viewingHero : null}
                actions={actions}
                buildings={buildings}
                heroBonds={heroBonds}
                heroes={heroes}
            />

            {heroes.map(hero => {
                const contributions = getContributingSynergies(hero);

                return (
                    <div key={hero.id} className={`relative p-2 rounded border-2 flex flex-col gap-1 transition-all 
                        ${!hero.unlocked ? 'border-gray-700 bg-gray-900 group/locked' :
                            hero.isMutated ? 'border-red-600 bg-red-950/30 shadow-[inset_0_0_15px_rgba(220,38,38,0.3)] animate-pulse hover:bg-gray-600' :
                            hero.isAwakened ? 'border-yellow-500 bg-gray-700 shadow-[inset_0_0_15px_rgba(234,179,8,0.2)] hover:bg-gray-600' :
                            'border-gray-600 bg-gray-700 hover:bg-gray-600'
                        }`}>
                        {!hero.unlocked && (
                            <div className="absolute inset-0 flex items-center justify-center bg-black/40 opacity-0 group-hover/locked:opacity-100 transition-opacity z-10 rounded">
                                <button
                                    onClick={() => actions.buyHero(hero.id)}
                                    className="bg-amber-600 hover:bg-amber-500 text-white text-[10px] font-bold py-1 px-2 rounded border border-amber-400 shadow-lg"
                                >
                                    RECRUTAR (5000o)
                                </button>
                            </div>
                        )}
                        <div className="flex justify-between items-start">
                            <div className="flex items-center gap-1">
                                <span className="text-xl" role="img" aria-label={hero.name}>{hero.emoji}</span>
                                <div className="flex flex-col">
                                    <div className="flex items-center gap-1">
                                        <span className="text-xs font-bold text-white">{hero.name}</span>
                                        {hero.statPoints > 0 && (
                                            <span className="bg-yellow-500 text-black text-[8px] px-1 rounded-full animate-bounce font-black">UP!</span>
                                        )}
                                    </div>
                                    <div className="flex items-center gap-1">
                                        <span className="text-[10px] text-gray-400">{hero.class} (Nvl {hero.level}{hero.isAwakened ? ' ★' : ''})</span>
                                        {((hero.fatigue || 0) >= 50) && (
                                            <ShieldAlert size={10} className={(hero.fatigue || 0) >= 80 ? 'text-red-500 animate-pulse' : 'text-yellow-500'} />
                                        )}
                                        {hero.isAwakened && <Zap size={10} className="text-yellow-400 animate-pulse" />}
                                        {hero.isMutated && (
                                            <span className="text-[8px] bg-red-900 text-red-300 border border-red-600 px-1 rounded font-bold animate-pulse">
                                                💀 CORROMPIDO
                                            </span>
                                        )}
                                    </div>
                                </div>
                            </div>
                            {hero.unlocked && (
                                <div className="flex gap-1">

                                    <button
                                        onClick={() => actions.toggleAssignment(hero.id)}
                                        className={`p-1 rounded border ${hero.assignment === 'combat' ? 'bg-red-900 border-red-500 text-red-200' : 'bg-blue-900 border-blue-500 text-blue-200'}`}
                                    >
                                        {hero.assignment === 'combat' ? <Sword size={10} /> : <Pickaxe size={10} />}
                                    </button>
                                    <button
                                        onClick={() => actions.purifyHero(hero.id)}
                                        className={`p-1 rounded border ${hero.insanity >= 50 ? 'bg-purple-900 border-purple-500 text-purple-200 animate-pulse' : 'bg-gray-800 border-gray-600 text-gray-400'}`}
                                        title={`Purificar Herói (Reseta Insanidade) - Custo: 1000 de Ouro`}
                                        disabled={!hero.insanity || hero.insanity === 0}
                                    >
                                        <Skull size={10} />
                                    </button>

                                    <button
                                        onClick={() => setViewingHero(hero)}
                                        className="p-1 rounded bg-green-900 border border-green-500 text-green-200"
                                        title="Ver Status e Habilidades"
                                    >
                                        <Info size={10} />
                                    </button>
                                    {/* Phase 58: Evolution */}
                                    {hero.level >= 50 && (
                                        <button
                                            onClick={() => actions.evolveHero(hero.id)}
                                            className="p-1 rounded bg-gradient-to-tr from-yellow-600 to-yellow-300 border border-yellow-100 text-yellow-900 animate-pulse shadow-[0_0_10px_rgba(234,179,8,0.5)]"
                                            title="Evoluir Herói (Reseta Nvl para 1, Status Massivos!)"
                                        >
                                            <Crown size={10} />
                                        </button>
                                    )}
                                </div>
                            )}
                        </div>

                        {
                            hero.unlocked && (
                                <div className="flex flex-col gap-1 mt-1">

                                    <div className="grid grid-cols-2 gap-x-2 text-[9px] text-gray-300 mt-1">
                                        <div className="flex items-center gap-1"><Sword size={8} className="text-red-400" /> {hero.stats.attack}</div>
                                        <div className="flex items-center gap-1"><Shield size={8} className="text-yellow-400" /> {hero.stats.defense}</div>
                                        <div className="flex items-center gap-1"><Zap size={8} className="text-blue-400" /> {hero.stats.magic}</div>
                                        <div className="flex items-center gap-1"><Zap size={8} className="text-green-400" /> {hero.stats.speed}</div>
                                    </div>

                                    {/* Synergy Contribution Badges */}
                                    {contributions.length > 0 && hero.assignment === 'combat' && (
                                        <div className="flex gap-1 mt-1 border-t border-gray-700 pt-1 justify-end">
                                            {contributions.map(s => (
                                                <div key={s.id} title={`Contribui para: ${s.name}`} className="bg-black bg-opacity-50 rounded p-0.5 border border-gray-700">
                                                    {getSynergyIcon(s.type)}
                                                </div>
                                            ))}
                                        </div>
                                    )}
                                </div>
                            )
                        }
                    </div>
                )
            })}
        </div >
    );
};
